#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        map<ll,priority_queue<ll>> mp;        for(int i=0;i<n;i++){            cin>>a[i];            mp[-a[i]].push(i);        }        ll ans=0;        ll pidx=n;        for(auto x:mp){            while(!x.second.empty()){                ll idx=x.second.top();                x.second.pop();                if(idx<pidx) {                    ans++;                    pidx=idx;                }            }        }        cout<<ans<<endl;    }}